import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"장기수선계획 관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/long-term-repair.md","filePath":"guide/scenarios/long-term-repair.md","lastUpdated":null}'),s={name:"guide/scenarios/long-term-repair.md"};function i(o,a,n,d,h,c){return e(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="장기수선계획-관리" tabindex="-1">장기수선계획 관리 <a class="header-anchor" href="#장기수선계획-관리" aria-label="Permalink to &quot;장기수선계획 관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 검토 약 2시간 / 집행 건당 약 30분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 연 1회 검토 + 수시 집행</p></blockquote><p>공동주택관리법에 따라 의무적으로 수립·관리해야 하는 장기수선계획을 검토하고, 수선 공사를 집행하는 프로세스입니다.</p><div class="info custom-block"><p class="custom-block-title">충당금 관리는 경리 업무입니다</p><p>장기수선충당금 적립 현황 관리와 전출 시 충당금 정산은 경리 담당이 처리합니다. → <a href="/guide/scenarios/reserve-fund.html">장기수선충당금 관리</a></p></div><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><h3 id="계획-수립-및-검토-연-1회" tabindex="-1">계획 수립 및 검토 (연 1회) <a class="header-anchor" href="#계획-수립-및-검토-연-1회" aria-label="Permalink to &quot;계획 수립 및 검토 (연 1회)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 장기수선계획 수립   (외부 서비스) → 수선 항목·일정·비용 산정</span></span>
<span class="line"><span>2. 수선 항목 확인      (30분)        → 시설별 수선 주기·금액 검토</span></span>
<span class="line"><span>3. 입주자대표회의 의결 (별도)        → 계획 승인·변경 의결</span></span>
<span class="line"><span>4. 보고서 출력         (5분)         → 의결 결과 보관</span></span></code></pre></div><h3 id="수선-공사-집행-수시" tabindex="-1">수선 공사 집행 (수시) <a class="header-anchor" href="#수선-공사-집행-수시" aria-label="Permalink to &quot;수선 공사 집행 (수시)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 입주자대표회의 승인    (별도)  → 집행 전 의결</span></span>
<span class="line"><span>2. 공사비 전표 처리       (15분)  → 회계 &gt; 전표관리 입력</span></span>
<span class="line"><span>3. 예산 집행 확인         (5분)   → 예산관리 잔액 확인</span></span>
<span class="line"><span>4. 집행 이력 관리         (10분)  → 이력 기록·보관</span></span></code></pre></div><hr><h2 id="법적-의무-사항" tabindex="-1">법적 의무 사항 <a class="header-anchor" href="#법적-의무-사항" aria-label="Permalink to &quot;법적 의무 사항&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">공동주택관리법 의무 규정</p><ul><li><strong>수립 의무</strong>: 300세대 이상 또는 승강기가 있는 공동주택은 장기수선계획을 의무적으로 수립해야 합니다.</li><li><strong>정기 검토</strong>: <strong>3년마다</strong> 계획을 검토·조정해야 합니다.</li><li><strong>충당금 적립</strong>: 관리비와 함께 세대별로 매월 적립합니다.</li><li><strong>사용 승인</strong>: 수선 공사 집행 전에 <strong>입주자대표회의 의결</strong>이 필요합니다.</li></ul></div><hr><h2 id="_1단계-장기수선계획-수립-외부-서비스-연동" tabindex="-1">1단계: 장기수선계획 수립 (외부 서비스 연동) <a class="header-anchor" href="#_1단계-장기수선계획-수립-외부-서비스-연동" aria-label="Permalink to &quot;1단계: 장기수선계획 수립 (외부 서비스 연동)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: <a href="/afms/">장기수선계획</a></p></blockquote><p>메뉴 선택 시 <strong>외부 서비스 페이지로 이동</strong>합니다. 외부 서비스에서 아래 항목을 작성합니다.</p><h3 id="주요-작성-내용" tabindex="-1">주요 작성 내용 <a class="header-anchor" href="#주요-작성-내용" aria-label="Permalink to &quot;주요 작성 내용&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>수선 대상 시설</td><td>엘리베이터, 외벽, 지붕, 배관 등 주요 시설</td></tr><tr><td>수선 주기</td><td>시설별 법정 또는 권장 수선 주기</td></tr><tr><td>수선 방법</td><td>전면 교체 / 부분 보수 / 점검</td></tr><tr><td>예상 비용</td><td>시설별 공사 예상 금액</td></tr><tr><td>수선 연도</td><td>연도별 공사 계획</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">외부 서비스 이동</p><p>장기수선계획 메뉴 클릭 시 XpERP 외부의 전문 서비스로 이동합니다. 해당 서비스에서 작성한 계획이 시스템에 연동됩니다.</p></div><hr><h2 id="_2단계-수선-공사-집행" tabindex="-1">2단계: 수선 공사 집행 <a class="header-anchor" href="#_2단계-수선-공사-집행" aria-label="Permalink to &quot;2단계: 수선 공사 집행&quot;">​</a></h2><h3 id="집행-전-확인사항" tabindex="-1">집행 전 확인사항 <a class="header-anchor" href="#집행-전-확인사항" aria-label="Permalink to &quot;집행 전 확인사항&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">입주자대표회의 의결 필수</p><p>수선 공사를 집행하기 전에 반드시 <strong>입주자대표회의의 의결</strong>을 받아야 합니다. 의결 없이 집행하면 법적 문제가 발생할 수 있습니다.</p></div><ul><li>[ ] 장기수선계획에 포함된 항목인가?</li><li>[ ] 입주자대표회의 의결이 완료되었는가?</li><li>[ ] 예산 잔액이 충분한가?</li><li>[ ] 공사 계약 서류가 준비되었는가?</li></ul><h3 id="공사비-전표-처리" tabindex="-1">공사비 전표 처리 <a class="header-anchor" href="#공사비-전표-처리" aria-label="Permalink to &quot;공사비 전표 처리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 (ACCT2010)</p></blockquote><p>수선 공사비를 지출 전표로 기록합니다.</p><h4 id="입력-예시-엘리베이터-교체-공사비-50-000-000원" tabindex="-1">입력 예시: 엘리베이터 교체 공사비 50,000,000원 <a class="header-anchor" href="#입력-예시-엘리베이터-교체-공사비-50-000-000원" aria-label="Permalink to &quot;입력 예시: 엘리베이터 교체 공사비 50,000,000원&quot;">​</a></h4><table tabindex="0"><thead><tr><th>구분</th><th>계정과목</th><th>적요</th><th>금액</th></tr></thead><tbody><tr><td><strong>차변</strong></td><td>장기수선충당금 사용</td><td>엘리베이터 교체 공사비</td><td>50,000,000</td></tr><tr><td><strong>대변</strong></td><td>보통예금 (충당금 계좌)</td><td>엘리베이터 교체 대금 지급</td><td>50,000,000</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">전표 입력 자세한 방법</p><p>전표 입력 절차는 <a href="/guide/scenarios/expense-voucher.html">지출 전표 입력</a> 시나리오를 참고하세요.</p></div><h3 id="예산-집행-확인" tabindex="-1">예산 집행 확인 <a class="header-anchor" href="#예산-집행-확인" aria-label="Permalink to &quot;예산 집행 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a></p></blockquote><p>공사비 집행 후 예산 잔액을 확인합니다.</p><ul><li>당초 예산 vs 집행액 비교</li><li>잔여 예산 확인</li><li>예산 초과 시 추가 편성 필요</li></ul><hr><h2 id="_3단계-정기-검토-3년마다" tabindex="-1">3단계: 정기 검토 (3년마다) <a class="header-anchor" href="#_3단계-정기-검토-3년마다" aria-label="Permalink to &quot;3단계: 정기 검토 (3년마다)&quot;">​</a></h2><h3 id="검토-절차" tabindex="-1">검토 절차 <a class="header-anchor" href="#검토-절차" aria-label="Permalink to &quot;검토 절차&quot;">​</a></h3><ol><li>기존 장기수선계획 조회 (외부 서비스)</li><li>실제 시설 상태와 비교 검토: <ul><li>계획대로 수선이 이루어졌는가?</li><li>추가 수선이 필요한 시설은 없는가?</li><li>공사 단가 변동이 반영되었는가?</li></ul></li><li>계획 수정·조정</li><li>입주자대표회의 의결 → 변경 계획 확정</li><li>보고서 출력·보관</li></ol><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 전기 시설 (수변전설비, 배선) 점검 이력 확인</li><li>[ ] 기계 시설 (급수·오수·소방 설비) 수선 상태 확인</li><li>[ ] 건축물 (외벽, 지붕, 복도) 노후화 상태 확인</li><li>[ ] 엘리베이터 정기 검사 결과 반영</li><li>[ ] 충당금 잔액이 향후 계획 집행에 충분한가?</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="장기수선계획-메뉴에-들어가면-외부-페이지로-이동해요" tabindex="-1">장기수선계획 메뉴에 들어가면 외부 페이지로 이동해요 <a class="header-anchor" href="#장기수선계획-메뉴에-들어가면-외부-페이지로-이동해요" aria-label="Permalink to &quot;장기수선계획 메뉴에 들어가면 외부 페이지로 이동해요&quot;">​</a></h3><p><strong>원인</strong>: 장기수선계획은 외부 전문 서비스와 연동됩니다. <strong>해결</strong>: 정상적인 동작입니다. 외부 페이지에서 작업을 진행하세요. 접속이 안 되면 네트워크 상태를 확인하거나 관리자에게 문의하세요.</p><h3 id="수선-공사-집행-후-예산이-초과되었어요" tabindex="-1">수선 공사 집행 후 예산이 초과되었어요 <a class="header-anchor" href="#수선-공사-집행-후-예산이-초과되었어요" aria-label="Permalink to &quot;수선 공사 집행 후 예산이 초과되었어요&quot;">​</a></h3><p><strong>원인</strong>: 공사 예산 편성 금액보다 실제 공사비가 증가한 경우 <strong>해결</strong>: <a href="/acct/budget.html">예산관리</a>에서 추가 예산을 편성하고 입주자대표회의의 추가 의결을 받아야 합니다.</p><h3 id="_3년-검토-시기를-놓쳤어요" tabindex="-1">3년 검토 시기를 놓쳤어요 <a class="header-anchor" href="#_3년-검토-시기를-놓쳤어요" aria-label="Permalink to &quot;3년 검토 시기를 놓쳤어요&quot;">​</a></h3><p><strong>원인</strong>: 정기 검토 일정 관리 미흡 <strong>해결</strong>: 즉시 검토를 진행하고 입주자대표회의에 보고하세요. 검토 이력은 관련 서류로 보관하고, 이후에는 연초 업무 계획에 검토 일정을 포함하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/afms/">장기수선계획</a> - 계획 수립·조회 (외부 서비스 연동)</li><li><a href="/guide/scenarios/reserve-fund.html">장기수선충당금 관리</a> - 충당금 적립·전출 정산 (경리 업무)</li><li><a href="/acct/voucher.html">전표관리</a> - 공사비 지출 전표 입력</li><li><a href="/acct/budget.html">예산관리</a> - 집행 예산 확인</li></ul>`,51)])])}const b=t(s,[["render",i]]);export{u as __pageData,b as default};
